global.schema:
enum SurveyKind {
  SURVEY
  TEMPLATE
}

enum SurveyStatus {
  DRAFT
  OPEN
  CLOSED
}

enum QuestionType {
  SHORT_TEXT
  LONG_TEXT
  SINGLE_SELECT
  MULTI_SELECT
  RATING
  GRID
}

enum GridColumnType {
  TEXT
  SELECT
}

type QuestionOption {
  id: OID!
  label: String!
}

type RatingScale {
  min: Int!
  max: Int!
  minLabel: String
  maxLabel: String
}

type GridColumn {
  id: OID!
  label: String!
  type: GridColumnType!
  options: [QuestionOption!]!
}

type SurveySection {
  id: OID!
  title: String!
  description: String
}

type SurveyQuestion {
  id: OID!
  sectionId: OID!
  type: QuestionType!
  title: String!
  helpText: String
  required: Boolean!
  options: [QuestionOption!]!
  ratingScale: RatingScale
  columns: [GridColumn!]!
}

type GridCell {
  columnId: OID!
  text: String
  optionId: OID
}

type GridRow {
  cells: [GridCell!]!
}

type Answer {
  questionId: OID!
  text: String
  optionIds: [OID!]!
  rating: Int
  rows: [GridRow!]!
}

type SurveyResponse {
  id: OID!
  submittedAt: DateTime!
  answers: [Answer!]!
}

type SurveyState {
  title: String!
  description: String
  kind: SurveyKind!
  status: SurveyStatus!
  shareToken: String
  clientId: PHID
  clientName: String
  sections: [SurveySection!]!
  questions: [SurveyQuestion!]!
  responses: [SurveyResponse!]!
  createdAt: DateTime
  publishedAt: DateTime
  closedAt: DateTime
}

operations.schema:
input SetRecipientInput {
  clientId: PHID
  clientName: String
}

input AddSectionInput {
  id: OID!
  title: String!
  description: String
}

operations.reducer:
state.sections.push({
  id: action.input.id,
  title: action.input.title,
  description: action.input.description || null,
});

operations.schema:
input UpdateSectionInput {
  id: OID!
  title: String
  description: String
}

operations.reducer:
const section = state.sections.find((s) => s.id === action.input.id);
if (!section) {
  throw new SectionNotFoundError(`Section ${action.input.id} not found`);
}
if (action.input.title) {
  section.title = action.input.title;
}
if (typeof action.input.description === "string") {
  section.description = action.input.description || null;
}

const index = state.sections.findIndex((s) => s.id === action.input.id);
if (index === -1) {
  throw new SectionNotFoundError(`Section ${action.input.id} not found`);
}
state.sections.splice(index, 1);
state.questions = state.questions.filter((q) => q.sectionId !== action.input.id);

const byId = new Map(state.sections.map((s) => [s.id, s]));
const reordered = [];
for (const id of action.input.order) {
  const section = byId.get(id);
  if (!section) {
    throw new SectionNotFoundError(`Section ${id} not found`);
  }
  reordered.push(section);
  byId.delete(id);
}
for (const section of byId.values()) {
  reordered.push(section);
}
state.sections = reordered;

if (!state.sections.some((s) => s.id === action.input.sectionId)) {
  throw new SectionNotFoundError(`Section ${action.input.sectionId} not found`);
}
state.questions.push({
  id: action.input.id,
  sectionId: action.input.sectionId,
  type: action.input.type,
  title: action.input.title,
  helpText: action.input.helpText || null,
  required: action.input.required ?? false,
  options: (action.input.options ?? []).map((o) => ({ id: o.id, label: o.label })),
  ratingScale: action.input.ratingScale
    ? {
        min: action.input.ratingScale.min,
        max: action.input.ratingScale.max,
        minLabel: action.input.ratingScale.minLabel || null,
        maxLabel: action.input.ratingScale.maxLabel || null,
      }
    : null,
  columns: (action.input.columns ?? []).map((c) => ({
    id: c.id,
    label: c.label,
    type: c.type,
    options: (c.options ?? []).map((o) => ({ id: o.id, label: o.label })),
  })),
});

operations.schema:
input UpdateQuestionInput {
  id: OID!
  type: QuestionType!
  title: String!
  helpText: String
  required: Boolean
  options: [UpdateQuestionOptionInput!]
  ratingScale: UpdateQuestionRatingScaleInput
  columns: [UpdateQuestionColumnInput!]
}

input UpdateQuestionOptionInput {
  id: OID!
  label: String!
}

input UpdateQuestionRatingScaleInput {
  min: Int!
  max: Int!
  minLabel: String
  maxLabel: String
}

input UpdateQuestionColumnInput {
  id: OID!
  label: String!
  type: GridColumnType!
  options: [UpdateQuestionOptionInput!]
}

operations.reducer:
const question = state.questions.find((q) => q.id === action.input.id);
if (!question) {
  throw new QuestionNotFoundError(`Question ${action.input.id} not found`);
}
question.type = action.input.type;
question.title = action.input.title;
question.helpText = action.input.helpText || null;
question.required = action.input.required ?? false;
question.options = (action.input.options ?? []).map((o) => ({ id: o.id, label: o.label }));
question.ratingScale = action.input.ratingScale
  ? {
      min: action.input.ratingScale.min,
      max: action.input.ratingScale.max,
      minLabel: action.input.ratingScale.minLabel || null,
      maxLabel: action.input.ratingScale.maxLabel || null,
    }
  : null;
question.columns = (action.input.columns ?? []).map((c) => ({
  id: c.id,
  label: c.label,
  type: c.type,
  options: (c.options ?? []).map((o) => ({ id: o.id, label: o.label })),
}));

const index = state.questions.findIndex((q) => q.id === action.input.id);
if (index === -1) {
  throw new QuestionNotFoundError(`Question ${action.input.id} not found`);
}
state.questions.splice(index, 1);

operations.schema:
input MoveQuestionInput {
  id: OID!
  sectionId: OID!
}

operations.reducer:
const question = state.questions.find((q) => q.id === action.input.id);
if (!question) {
  throw new QuestionNotFoundError(`Question ${action.input.id} not found`);
}
if (!state.sections.some((s) => s.id === action.input.sectionId)) {
  throw new SectionNotFoundError(`Section ${action.input.sectionId} not found`);
}
question.sectionId = action.input.sectionId;

const byId = new Map(state.questions.map((q) => [q.id, q]));
const reordered = [];
for (const id of action.input.order) {
  const question = byId.get(id);
  if (!question) {
    throw new QuestionNotFoundError(`Question ${id} not found`);
  }
  reordered.push(question);
  byId.delete(id);
}
for (const question of byId.values()) {
  reordered.push(question);
}
state.questions = reordered;

operations.schema:
input PublishSurveyInput {
  shareToken: String!
  publishedAt: DateTime!
}

operations.reducer:
if (state.kind === "TEMPLATE") {
  throw new CannotPublishTemplateError("Templates cannot be published");
}
state.status = "OPEN";
state.shareToken = action.input.shareToken;
state.publishedAt = action.input.publishedAt;
state.closedAt = null;

if (state.kind === "TEMPLATE") {
  throw new CannotPublishTemplateError("Templates cannot be published");
}
state.status = "OPEN";
state.closedAt = null;

operations.schema:
input AddResponseInput {
  id: OID!
  submittedAt: DateTime!
  answers: [AddResponseAnswerInput!]!
}

input AddResponseAnswerInput {
  questionId: OID!
  text: String
  optionIds: [OID!]
  rating: Int
  rows: [AddResponseRowInput!]
}

input AddResponseRowInput {
  cells: [AddResponseCellInput!]!
}

input AddResponseCellInput {
  columnId: OID!
  text: String
  optionId: OID
}

operations.reducer:
if (state.status !== "OPEN") {
  throw new SurveyNotOpenError("Survey is not accepting responses");
}
const known = new Set(state.questions.map((q) => q.id));
for (const answer of action.input.answers) {
  if (!known.has(answer.questionId)) {
    throw new UnknownQuestionError(`Question ${answer.questionId} not found`);
  }
}
state.responses.push({
  id: action.input.id,
  submittedAt: action.input.submittedAt,
  answers: action.input.answers.map((answer) => ({
    questionId: answer.questionId,
    text: answer.text || null,
    optionIds: answer.optionIds ?? [],
    rating: answer.rating ?? null,
    rows: (answer.rows ?? []).map((row) => ({
      cells: row.cells.map((cell) => ({
        columnId: cell.columnId,
        text: cell.text || null,
        optionId: cell.optionId || null,
      })),
    })),
  })),
});

const index = state.responses.findIndex((r) => r.id === action.input.id);
if (index === -1) {
  throw new ResponseNotFoundError(`Response ${action.input.id} not found`);
}
state.responses.splice(index, 1);
